#!/usr/bin/env bash
# forecast-a-quarter-rep-side.sh — Forecast a quarter (rep side)（预测一个季度——销售个人侧） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Forecast a quarter (rep side)（预测一个季度——销售个人侧）"

usage() {
  cat <<EOF
forecast-a-quarter-rep-side.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./forecast-a-quarter-rep-side.sh             # interactive
  ./forecast-a-quarter-rep-side.sh --dry-run
  ./forecast-a-quarter-rep-side.sh --json
  ./forecast-a-quarter-rep-side.sh --explain
  ./forecast-a-quarter-rep-side.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Forecast a quarter (rep side)（预测一个季度——销售个人侧）" 工作流。

一句话: Turn a pile of open deals into a *defensible* number — inspect each deal, categorize it honestly (commit / best case / pipeline), and own the commit. The discipline that separates a trusted rep from "happy ears." (evidence: [T03-S018, T03-S022])

入门 SOP 共 4 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Inspect each deal against evidence** — for every open opp, ask the deal-inspection questions: what % of the buyer's broader problem does this solve? has someone with decision power acknowledged the problem? what precedent exists for approving this spend? what changed since last contact? (evidence: [T03-S018])"
  "**Confirm the close date is real** — tie it to the buyer's decision process / a critical event, not a hopeful guess. (evidence: [T03-S019])"
  "**Categorize honestly** — Commit (90-95%, a near-promise), Best Case (50-70%, material risk), Pipeline (15-30%, longshots); categories are *confidence buckets*, orthogonal to deal stage. (evidence: [T03-S022])"
  "**Respect the commit bank account** — commit only up to (never above) the total value of your genuinely-committed deals. (evidence: [T03-S018])"
)
declare -a FAILURE_MODES=(
  "**Happy ears — committing deals on optimism, not evidence**: \"the buyer loved it\" is not a forecast. Avoid: commit only with MEDDPICC evidence (named EB, mapped decision process, real close date). (evidence: [T03-S018, T03-S005])"
  "**Miscategorizing best-case as commit**: blows the team number and your credibility. Avoid: treat categories as confidence buckets with explicit thresholds (commit = 90-95%). (evidence: [T03-S022])"
  "**Hopeful close dates → repeated slips**: erodes forecast trust deal by deal. Avoid: tie the close date to the buyer's decision process / a critical event. (evidence: [T03-S019])"
  "**Sandbagging (chronically closing above commit)**: hiding commits in best-case erodes trust the other direction and distorts capacity planning. Avoid: forecast to the commit-bank — honest, not gamed. (evidence: [T03-S018])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "forecast-a-quarter-rep-side-walkthrough"
fi
